$assemblyRegistry = @{
    'Microsoft.Bcl.AsyncInterfaces' = { ,[Convert]::FromBase64String($b64_Microsoft_Bcl_AsyncInterfaces) }
    'Microsoft.Bcl.TimeProvider' = { ,[Convert]::FromBase64String($b64_Microsoft_Bcl_TimeProvider) }
    'ObfuscatorLauncher' = { ,[Convert]::FromBase64String($b64_ObfuscatorLauncher) }
    'Spectre.Console.Ansi' = { ,[Convert]::FromBase64String($b64_Spectre_Console_Ansi) }
    'Spectre.Console' = { ,[Convert]::FromBase64String($b64_Spectre_Console) }
    'System.Buffers' = { ,[Convert]::FromBase64String($b64_System_Buffers) }
    'System.Memory' = { ,[Convert]::FromBase64String($b64_System_Memory) }
    'System.Numerics.Vectors' = { ,[Convert]::FromBase64String($b64_System_Numerics_Vectors) }
    'System.Runtime.CompilerServices.Unsafe' = { ,[Convert]::FromBase64String($b64_System_Runtime_CompilerServices_Unsafe) }
    'System.Threading.Tasks.Extensions' = { ,[Convert]::FromBase64String($b64_System_Threading_Tasks_Extensions) }
}

[AppDomain]::CurrentDomain.add_AssemblyResolve({
    param($sender, $resolveArgs)
    $simpleName = ($resolveArgs.Name -split ',')[0].Trim()
    if ($assemblyRegistry.ContainsKey($simpleName)) {
        return [Reflection.Assembly]::Load((& $assemblyRegistry[$simpleName]))
    }
    return $null
}.GetNewClosure())

if ('ObfuscatorLauncher.Launcher' -as [type]) {
    Write-Warning "Types already loaded -- restart PowerShell to pick up rebuilds."
}

$entryAsm     = [Reflection.Assembly]::Load((& $assemblyRegistry['ObfuscatorLauncher']))
$launcherType = $entryAsm.GetType('ObfuscatorLauncher.Launcher', $true)
$runMenu      = $launcherType.GetMethod('RunMenu', [Reflection.BindingFlags] 'Static, Public')
$runMenu.Invoke($null, $null)
